/* Contenedor del Rich Text: barra centrada y con ancho controlado */
[selector='accordion-solid']{
  display:block;
  width:98%;              /* ocupa menos que el full */
  margin:22px auto;       /* centra horizontalmente */
  justify-self:center;    /* si el padre es grid */
  align-self:center;      /* si el padre es flex-col */
  margin-bottom: 0px;
}

/* Bloque visual de la barra sólida */
[selector='accordion-solid'] .form-group > div > div{
  display:flex;
  align-items:center;           /* centra verticalmente el texto */
  justify-content:flex-start;   /* texto a la izquierda */
  width:100%;                   /* llena el contenedor centrado */
  padding:12px 20px;
  background:#2167AE;           /* azul sólido */
  color:#fff;
  border-radius: 4px;              /* si la quieres recta */
  box-sizing:border-box;
}

/* Texto: blanco, mayúsculas, sin márgenes */
[selector='accordion-solid'] p{
  margin:0;
  color:#fff !important;
  line-height:1;
  letter-spacing:.3px;
  text-transform:uppercase;
}


[selector='accordiones'] {
  margin-top: 22px;
  margin-bottom: 22px;
  background-color: #2167AE;
}

/* Botón de acordeón: ancho completo, texto a la izquierda, espacio para el icono */
[selector='accordiones'] .btn-primary {
  width: 100%;
  text-align: left;
  position: relative;
  padding-right: 37px; /* espacio para la flecha (FontAwesome) */
  /* Transición suave para cambios de fondo o color si los hubiera */
  transition: background-color 0.3s ease, color 0.3s ease;
}

/* Pseudo-elemento ::after que inserta la flecha con Font Awesome */
[selector='accordiones'] .btn-primary::after {
  /* FontAwesome 5 Free: Unicode f078 = "chevron-down" */
  font-family: "Font Awesome 5 Free";
  font-weight: 900;
  content: "\f078";
  position: absolute;
  top: 50%;
  right: 0.75rem;
  transform: translateY(-50%) rotate(0deg);
  font-size: 1rem;
  color: #ffffff;
  /* Transición suave al rotar la flecha */
  transition: transform 0.3s ease-in-out;
}

/* Cuando el botón tenga la clase .open (panel abierto), girar la flecha */
[selector='accordiones'] .btn-primary.open::after {
  transform: translateY(-50%) rotate(180deg);
}

/* Opcional: cambiar ligeramente el fondo al pasar el ratón */
[selector='accordiones'] .btn-primary:hover {
  background-color: #1b5c99;
}


