/* BASE: badge sólido, sin borde, texto blanco */
[selector^='Status-'] .form-group {
  display: inline-block;
  margin: 2px 6px 0 0;
}
[selector^='Status-'] .form-group > div > div {
  display: inline-flex;            /* icono + texto */
  align-items: center;             /* centra vertical */
  gap: 6px;
  padding: 6px 12px;
  border-radius: 999px;
  border: none !important;         /* sin borde */
  background: var(--bg, #6f42c1);  /* color por estado */
  color: #fff !important;          /* texto/ícono blanco */
  box-shadow: 0 1px 2px rgba(0,0,0,.12);
  font-weight: 700;
  font-size: 12px;
  line-height: 1;
  white-space: nowrap;
  vertical-align: middle;
  transition: filter .15s ease;
}
[selector^='Status-'] .form-group > div > div:hover { filter: brightness(1.03); }
[selector^='Status-'] p { margin: 0; }

/* Ícono blanco (Font Awesome 5/6) */
[selector^='Status-'] .form-group > div > div::before {
  font-family: "Font Awesome 6 Free","Font Awesome 5 Free";
  font-weight: 900;
  font-size: 12px;
  line-height: 1;
  color: currentColor;             /* blanco */
  content: "";
}

/* ===== COLORES + ÍCONOS ===== */

/* CARGADO – MORADO sólido (NO azul), ícono file-upload */
[selector='Status-Cargado'] .form-group > div > div {
  --bg: #6f42c1;                   /* morado */
}
[selector='Status-Cargado'] .form-group > div > div::before {
  content: "\f574";                /* fa-file-upload */
  /* si no aparece, usar "\f093" (fa-upload) */
}

/* ACEPTADO – verde sólido, check-circle */
[selector='Status-Aceptado'] .form-group > div > div {
  --bg: #198754;                   /* success */
}
[selector='Status-Aceptado'] .form-group > div > div::before {
  content: "\f058";                /* fa-check-circle */
}

/* RECHAZADO – rojo sólido, times-circle */
[selector='Status-Rechazado'] .form-group > div > div {
  --bg: #dc3545;                   /* danger */
}
[selector='Status-Rechazado'] .form-group > div > div::before {
  content: "\f057";                /* fa-times-circle */
}

/* PENDIENTE – naranja sólido, hourglass-half */
[selector='Status-Pendiente'] .form-group > div > div {
  --bg: #fd7e14;                   /* warning */
}
[selector='Status-Pendiente'] .form-group > div > div::before {
  content: "\f252";                /* fa-hourglass-half */
}

/* Poner el texto en blanco dentro de los 4 estados */
[selector^='Status-'] p,
[selector^='Status-'] p strong {
  color: #fff !important;
  margin-bottom: 0px !important; 
}


/* Fallback sin Font Awesome (opcional)
[selector='Status-Cargado']   .form-group > div > div::before { content: "⤴️"; font-family: inherit; }
[selector='Status-Aceptado']  .form-group > div > div::before { content: "✔️"; font-family: inherit; }
[selector='Status-Rechazado'] .form-group > div > div::before { content: "✖️"; font-family: inherit; }
[selector='Status-Pendiente'] .form-group > div > div::before { content: "⏳"; font-family: inherit; }
